  ('social-worker-moex-08160', 'social-worker', 'social-worker-moex-098-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '個案工作的實施理論有多種學派，其中問題解決學派特別強調處理案主當前的問題與處在環境中的困境， 提出有名解決問題的四個「P」，是指：', '["Person、Problem、Place、Profession", "Person、Problem、Provision、Process", "Person、Place、Process、Profession", "Person、Problem、Place、Process"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "7fed7f8adbf8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 25, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08161', 'social-worker', 'social-worker-moex-098-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '「接案」是個案工作程序的首要步驟，下列何者並非初步接案工作結束前，所需達成的任務？', '["充分確認問題，以便確實符合服務的目的", "機構的服務適合協助此個案的問題", "個案的問題是社會工作者能力和技巧所能勝任的", "對個案問題作分析和干預"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "7fed7f8adbf8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 26, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08162', 'social-worker', 'social-worker-moex-098-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '當專業倫理發生兩難狀況時，在處理原則上，工作者應決定那一個原則為優先？', '["最小傷害原則", "隱私保密原則", "自主自由原則", "保護案主生命原則"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "7fed7f8adbf8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 27, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08163', 'social-worker', 'social-worker-moex-098-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '何時才真正用「團體工作」之名，來表達以小團體作為社會工作實施對象的社會工作新方法？', '["1917年", "1927年", "1930年", "1940年"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "7fed7f8adbf8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 28, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08164', 'social-worker', 'social-worker-moex-098-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '團體有不同的類型，下述團體屬於何種類型？－「工作者將社區代表組成團體，討論日間照顧服務資源分 布及對政府提出日間照顧支援政策。」', '["組成團體（formed groups）", "自然團體（natural groups）", "處遇性團體（treatment groups）", "任務性團體（task groups）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "7fed7f8adbf8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 29, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08165', 'social-worker', 'social-worker-moex-098-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列何者為支持性團體？', '["學校的兒童團體，討論父母離婚對其生活的影響", "青少年的價值澄清團體", "醫院為有藥癮的人所組成的團體", "家扶中心為未來將成為寄養家庭的父母所組成的團體"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "7fed7f8adbf8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 30, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08166', 'social-worker', 'social-worker-moex-098-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列何者並非團體工作的核心價值觀？', '["不論膚色、信仰、年齡、國籍和社會階層，任何人都可以參與團體，並建立積極關係", "在民主參與的原則下，合作與共同決策的重要性", "團體中只有團體，沒有個人的自主性", "團體中的個別化應受到重視，任何一位成員所關切的事都會被處理"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "7fed7f8adbf8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 31, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08167', 'social-worker', 'social-worker-moex-098-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '團體動力源自於團體成員間互動所產生的力量，其中包括團體成員的溝通與互動模式。下列何者是以「團 體為中心」的溝通模式？', '["圓圈型：成員輪流講話", "熱椅子：團體領導者與成員之一來一往交換角色", "自由漂浮型：所有成員都有責任說話加以溝通", "輻射型：溝通是以領導者為中心向其他成員傳送"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "7fed7f8adbf8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 32, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08168', 'social-worker', 'social-worker-moex-098-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '工作者帶領團體進行，必須考慮空間和時間上的安排，下列何者不適當？', '["將椅子圍成圓圈，面對面安排", "工作者應該低調，選擇不顯眼的位置", "團體聚會的頻率，原則上以一週一次為準", "團體每次聚會時間，1至2小時是正常的"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "7fed7f8adbf8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 33, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08169', 'social-worker', 'social-worker-moex-098-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '團體工作者應熟悉團體動力的四個向度，下列何者為所有團體形成的基礎？', '["團體凝聚力", "團體文化", "溝通和互動模式", "團體規範或社會整合"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "7fed7f8adbf8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 34, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
